+#if DDSRT_HAVE_IPV6
 static bool ownaddrs_eq6 (const void *va, const void *vb)
 {
   union addr const * const a = va;
   union addr const * const b = vb;
   assert (a->a.sa_family == AF_INET6 && b->a.sa_family == AF_INET6);
