+static char *
+get_openssl_error_message_for_test(
+        void)
+{
+    BIO *bio = BIO_new(BIO_s_mem());
+    char *msg;
+    char *buf = NULL;
+    size_t len;
+
+    if (bio) {
+        ERR_print_errors(bio);
+        len = (uint32_t)BIO_get_mem_data (bio, &buf);
+        msg = ddsrt_malloc(len + 1);
+        memset(msg, 0, len+1);
+        memcpy(msg, buf, len);
+        BIO_free(bio);
+    } else {
+        msg = ddsrt_strdup("BIO_new failed");
+    }
+
+    return msg;
+}
