+static void
+set_binary_property_string(
+     DDS_Security_BinaryProperty_t *bp,
+     const char *name,
+     const char *data)
+{
+    uint32_t length;
+
+    assert(bp);
+    assert(name);
+    assert(data);
+
+    length = (uint32_t)strlen(data) + 1;
+    set_binary_property_value(bp, name, (const unsigned char *)data, length);
+}
