+static X509 *
+load_certificate(
+   const char *data)
+{
+    X509 *cert = NULL;
+    BIO *bio;
+
+    bio = BIO_new_mem_buf((void *) data, -1);
+    if (!bio) {
+        return NULL;
+    }
+
+    cert = PEM_read_bio_X509(bio, NULL, NULL, NULL);
+
+    BIO_free(bio);
+
+    return cert;
+}
