+static dds_return_t
+dds_dispose_impl(
+       _In_ dds_writer *wr,
+       _In_ const void *data,
+       _In_ dds_instance_handle_t handle,
+       _In_ dds_time_t timestamp)
+{
+    dds_return_t ret;
+    assert(wr);
+    ret = dds_write_impl(wr, data, timestamp, DDS_WR_ACTION_DISPOSE);
+    if (ret == DDS_RETCODE_OK) {
+        dds_instance_remove (wr->m_topic, data, handle);
+    }
+    return ret;
+}
