+{
+    dds_return_t ret;
+    dds__retcode_t rc;
+    dds_writer *wr;
+
+    DDS_REPORT_STACK();
+
+    rc = dds_writer_lock(writer, &wr);
+    if (rc == DDS_RETCODE_OK) {
+        ret = dds_dispose_impl(wr, data, DDS_HANDLE_NIL, timestamp);
+        dds_writer_unlock(wr);
+    } else {
+        ret = DDS_ERRNO(rc, "Error occurred on locking writer");
+    }
