+uint32_t
+dds_reader_lock_samples(
+        dds_entity_t reader)
+{
+    uint32_t ret = 0;
+    dds_reader *rd;
+
+    ret = dds_reader_lock(reader, &rd);
+    if (ret == DDS_RETCODE_OK) {
+        ret = dds_rhc_lock_samples(rd->m_rd->rhc);
